# Search hadith texts for any uses of غذاء (غذاوة / غذاء)
def search_hadith_contains(term):
    nterm = normalize_ar(term)
    results=[]
    for d in hadith_data:
        for k in ('Matn','hadithTxt'):
            s = d.get(k)
            if not s:
                continue
            if nterm in normalize_ar(s):
                results.append((d['hadithID'], d['BookID'], d['title'], k, s))
                break
    return results

